INSERT INTO catalog_item (id, name, description, price, picture_file_name, catalog_type_id, catalog_brand_id, available_stock, restock_threshold, max_stock_threshold) VALUES
('11a22b33-c44d-55e6-7788-99aabbccdd00', '华为Mate 60 Pro', '搭载麒麟9000S自研处理器与鸿蒙系统，首创卫星通话功能，6.82英寸LTPO OLED曲面屏，昆仑玻璃面板，支持88W有线超级快充与50W无线充电', 6999.00, 'huawei_mate60pro.jpg', '1a2b3c4d-5e6f-7890-abcd-ef1234567890', 'a1b2c3d4-e5f6-7890-abcd-ef1234567890', 150, 20, 500),
('22b33c44-d55e-66f7-8899-aabbccddeeff', '小米14 Ultra', '搭载骁龙8 Gen 3旗舰处理器与徕卡光学四摄系统，支持可变光圈主摄，6.73英寸2K LTPO屏幕，IP68级防尘防水，配备90W有线快充与80W无线充电', 5999.00, 'xiaomi_14ultra.jpg', '1a2b3c4d-5e6f-7890-abcd-ef1234567890', 'b2c3d4e5-f6a7-8901-bcde-f12345678901', 200, 30, 600),
('33c44d55-e66f-77a8-9900-bbccddeeffaa', 'iPhone 15 Pro Max', '搭载A17 Pro仿生芯片与iOS生态系统，钛金属边框轻盈坚固，6.7英寸超视网膜XDR显示屏，首次采用USB-C接口，支持ProMotion自适应刷新率与5倍光学变焦', 9999.00, 'iphone_15promax.jpg', '1a2b3c4d-5e6f-7890-abcd-ef1234567890', 'c3d4e5f6-a7b8-9012-cdef-123456789012', 180, 25, 550),
('44d55e66-f77a-88b9-0011-ccddeeffaabb', '三星Galaxy S24 Ultra', '搭载骁龙8 Gen 3处理器与Galaxy AI智能助手，内置S Pen手写笔，2亿像素AI增强主摄，6.8英寸Dynamic AMOLED 2X平面屏幕，钛金属机身支持IP68防水', 8999.00, 'samsung_s24ultra.jpg', '1a2b3c4d-5e6f-7890-abcd-ef1234567890', 'd4e5f6a7-b8c9-0123-def1-234567890123', 120, 15, 400),
('55e66f77-a88b-99c0-0111-ddeeffaabbcc', 'OPPO Find X7 Ultra', '搭载骁龙8 Gen 3处理器与哈苏大师影像系统，独创双潜望长焦镜头组合，6.82英寸2K钻石曲面屏，支持100W超级闪充与50W无线充电，三段式物理静音键', 5999.00, 'oppo_findx7ultra.jpg', '1a2b3c4d-5e6f-7890-abcd-ef1234567890', 'e5f6a7b8-c9d0-1234-ef12-345678901234', 100, 20, 350),
('66f77a88-b99c-00d1-1122-eeffaabbccdd', '华为MatePad Pro 13.2', '配备13.2英寸柔性OLED全面屏与星闪无线连接技术，搭载麒麟9000S处理器，支持华为M-Pencil第三代手写笔与智能磁吸键盘，超薄机身仅5.5毫米', 5499.00, 'huawei_matepadpro132.jpg', '2b3c4d5e-6f7a-8901-bcde-f12345678901', 'a1b2c3d4-e5f6-7890-abcd-ef1234567890', 80, 10, 200),
('77a88b99-c00d-11e2-2233-ffaabbccddee', 'iPad Pro 12.9英寸', '搭载M2桌面级芯片与iPadOS系统，12.9英寸Liquid Retina XDR mini-LED显示屏，支持Apple Pencil悬停功能与妙控键盘，雷雳接口高速传输，兼顾创意与移动办公', 8499.00, 'ipad_pro129.jpg', '2b3c4d5e-6f7a-8901-bcde-f12345678901', 'c3d4e5f6-a7b8-9012-cdef-123456789012', 90, 15, 250),
('88b99c00-d11e-22f3-3344-aabbccddeeff', '小米平板6 Max', '配备14英寸2.8K分辨率超大屏幕与骁龙8+处理器，支持67W秒充与10000mAh大容量电池，八扬声器立体声系统环绕音效，多任务分屏办公娱乐两不误', 3299.00, 'xiaomi_pad6max.jpg', '2b3c4d5e-6f7a-8901-bcde-f12345678901', 'b2c3d4e5-f6a7-8901-bcde-f12345678901', 120, 20, 300),
('99c00d11-e22f-33a4-4455-bbccddeeffaa', '华为MateBook X Pro', '14.2英寸3.1K OLED原色全面触控屏，英特尔13代酷睿Evo认证处理器，机身仅重1.26千克，超级终端多设备协同，四麦克风AI降噪，金属微绒机身质感出众', 11999.00, 'huawei_matebookxpro.jpg', '3c4d5e6f-7a8b-9012-cdef-123456789012', 'a1b2c3d4-e5f6-7890-abcd-ef1234567890', 60, 10, 150),
('00d11e22-f33a-44b5-5566-ccddeeffaabb', 'MacBook Pro 14英寸', '搭载M3 Pro芯片与macOS系统，14.2英寸Liquid Retina XDR显示屏支持120Hz ProMotion，长达17小时电池续航，MagSafe磁吸充电与雷雳4接口，专业创作利器', 14999.00, 'macbook_pro14.jpg', '3c4d5e6f-7a8b-9012-cdef-123456789012', 'c3d4e5f6-a7b8-9012-cdef-123456789012', 70, 12, 180),
('11e22f33-a44b-55c6-6677-ddeeffaabbcc', '联想ThinkPad X1 Carbon', '14英寸2.8K OLED防蓝光护眼屏幕，英特尔13代酷睿vPro商用处理器，通过MIL-STD-810H军工级严苛测试，碳纤维编织机身仅重1.12千克，商务出行理想伴侣', 12999.00, 'lenovo_thinkpadx1.jpg', '3c4d5e6f-7a8b-9012-cdef-123456789012', 'a7b8c9d0-e1f2-3456-0123-567890123456', 50, 8, 120),
('22f33a44-b55c-66d7-7788-eeffaabbccdd', '戴尔XPS 15', '15.6英寸3.5K OLED触控全面屏四边极窄边框，英特尔13代酷睿H系列标压处理器，CNC一体成型铝合金机身，四扬声器Waves MaxxAudio调音，Windows Hello人脸识别', 13999.00, 'dell_xps15.jpg', '3c4d5e6f-7a8b-9012-cdef-123456789012', 'b8c9d0e1-f2a3-4567-1234-678901234567', 45, 8, 100),
('33a44b55-c66d-77e8-8899-ffaabbccddee', '华为Watch GT 4', '1.43英寸AMOLED圆形高清表盘搭载HarmonyOS，支持心率血氧体温三环全天候监测，14天超长续航无需频繁充电，100余种运动模式精准记录，支持蓝牙通话独立播放音乐', 1488.00, 'huawei_watchgt4.jpg', '5e6f7a8b-9c0d-1234-ef12-345678901234', 'a1b2c3d4-e5f6-7890-abcd-ef1234567890', 200, 30, 500),
('44b55c66-d77e-88f9-9900-aabbccddeeff', 'Apple Watch Series 9', '搭载S9 SIP芯片与watchOS系统，全天候视网膜显示屏支持全新双指互点手势操作，精准心电图房颤提示与血氧饱和度检测，50米防水等级，运动健康全天候智能伴侣', 3199.00, 'apple_watch9.jpg', '5e6f7a8b-9c0d-1234-ef12-345678901234', 'c3d4e5f6-a7b8-9012-cdef-123456789012', 150, 25, 400),
('55c66d77-e88f-99a0-0011-bbccddeeffaa', '小米Watch S3', '1.43英寸AMOLED圆形屏幕搭载澎湃OS系统，支持150余种运动模式自动精准识别，12天典型续航，全天候血氧心率压力连续监测，蓝牙通话与独立支付功能一应俱全', 999.00, 'xiaomi_watchs3.jpg', '5e6f7a8b-9c0d-1234-ef12-345678901234', 'b2c3d4e5-f6a7-8901-bcde-f12345678901', 250, 40, 600),
('66d77e88-f99a-00b1-1122-ccddeeffaabb', 'AirPods Pro 2', '搭载Apple H2芯片实现2倍主动降噪深度，自适应通透模式智能调节环境声音，个性化空间音频动态头部追踪，MagSafe充电盒内置U1芯片扬声器支持精确查找与播放声音', 1899.00, 'airpods_pro2.jpg', '6f7a8b9c-0d1e-2345-f123-456789012345', 'c3d4e5f6-a7b8-9012-cdef-123456789012', 300, 50, 800),
('77e88f99-a00b-11c2-2233-ddeeffaabbcc', '华为FreeBuds Pro 3', '搭载麒麟A2芯片与星闪无线连接技术，智慧动态降噪3.0自适应场景切换，支持超CD级无损音频LDAC传输，多设备无缝流转切换，三麦克风骨声纹AI通话降噪清晰拾音', 1499.00, 'huawei_freebudspro3.jpg', '6f7a8b9c-0d1e-2345-f123-456789012345', 'a1b2c3d4-e5f6-7890-abcd-ef1234567890', 280, 45, 700),
('88f99a00-b11c-22d3-3344-eeffaabbccdd', '小米Buds 4 Pro', '搭载独立降噪芯片实现48dB宽频深度降噪，360度空间音频支持动态头部追踪，支持LDAC高清音频协议990kbps传输，三麦克风波束成形AI通话降噪，综合续航长达38小时', 999.00, 'xiaomi_buds4pro.jpg', '6f7a8b9c-0d1e-2345-f123-456789012345', 'b2c3d4e5-f6a7-8901-bcde-f12345678901', 320, 50, 750),
('99a00b11-c22d-33e4-4455-ffaabbccddee', '小爱音箱Pro', '内置小爱同学生成式AI语音助手与万能红外遥控模组，支持全屋智能家居语音控制管理，DTS专业调音立体声音效表现，AUX有线音频输入接口，可组建多房间音乐同步播放方案', 399.00, 'xiaomi_xiaiaipro.jpg', '7a8b9c0d-1e2f-3456-0123-567890123456', 'b2c3d4e5-f6a7-8901-bcde-f12345678901', 180, 30, 400),
('00b11c22-d33e-44f5-5566-aabbccddeeff', '华为Sound X', '帝瓦雷联合设计八单元三分频声学架构澎湃低音，HarmonyOS一碰传音极速连接，全场景超级终端智慧联动，48颗全色域LED幻彩灯效随音乐律动，智能空间感知算法自动声场校准', 1999.00, 'huawei_soundx.jpg', '7a8b9c0d-1e2f-3456-0123-567890123456', 'a1b2c3d4-e5f6-7890-abcd-ef1234567890', 100, 15, 250),
('11c22d33-e44f-55a6-6677-bbccddeeffaa', 'HomePod mini', '内置S5芯片与Siri智能语音助手，360度环绕声场支持空间音频感知计算音频技术，HomeKit智能家居中枢控制网关，内置温湿度传感器实时监测环境状态，广播传话功能全家无缝互联', 749.00, 'homepod_mini.jpg', '7a8b9c0d-1e2f-3456-0123-567890123456', 'c3d4e5f6-a7b8-9012-cdef-123456789012', 150, 25, 350),
('22d33e44-f55a-66b7-7788-ccddeeffaabb', '戴尔U2723QE显示器', '27英寸4K超高清分辨率IPS Black面板实现2000:1超高静态对比度，USB-C一线连接支持90W反向供电与数据传输，内置RJ45有线网口方便办公，出厂校色ΔE小于2专业色彩精准', 4999.00, 'dell_u2723qe.jpg', '8b9c0d1e-2f3a-4567-1234-678901234567', 'b8c9d0e1-f2a3-4567-1234-678901234567', 60, 10, 150),
('33e44f55-a66b-77c8-8899-ddeeffaabbcc', 'LG 27GP950-B显示器', '27英寸4K Nano IPS电竞级面板，原生144Hz高刷新率与1ms灰阶极速响应时间，HDMI 2.1满血接口完美适配PS5与XSX次世代游戏主机，兼容G-Sync与FreeSync Premium双重防撕裂技术', 4299.00, 'lg_27gp950.jpg', '8b9c0d1e-2f3a-4567-1234-678901234567', 'f2a3b4c5-d6e7-8901-5678-012345678901', 70, 12, 180),
('44f55a66-b77c-88d9-9900-eeffaabbccdd', '华硕ProArt PA279CV显示器', '27英寸4K分辨率IPS专业面板出厂逐台校色实现ΔE<2色准精度，覆盖100% sRGB与100% Rec.709广色域空间，USB-C支持65W供电与DisplayPort Alt Mode视频传输，专业设计师视频剪辑工作首选', 3299.00, 'asus_proart.jpg', '8b9c0d1e-2f3a-4567-1234-678901234567', 'd0e1f2a3-b4c5-6789-3456-890123456789', 55, 10, 140),
('55a66b77-c88d-99e0-0011-ffaabbccddee', '罗技MX Master 3S鼠标', '8000 DPI Darkfield高精度传感器可在任意表面甚至玻璃上精准追踪，MagSpeed电磁滚轮一秒滚动千行文档，静音微动按键设计安静办公，三设备跨平台Flow跨屏复制粘贴传输，USB-C快充', 799.00, 'logitech_mxmaster3s.jpg', '9c0d1e2f-3a4b-5678-2345-789012345678', 'e1f2a3b4-c5d6-7890-4567-901234567890', 200, 30, 500),
('66b77c88-d99e-00f1-1122-aabbccddeeff', 'HHKB Professional键盘', 'Topre静电容无触点轴体提供行云流水般的顺滑输入手感，60%紧凑精简布局缩短手指手腕移动范围，无刻键帽外观极致简约风格，DIP开关硬件级自定义键位功能，Unix配列习惯契合程序员使用姿势', 2499.00, 'hhkb_pro.jpg', '9c0d1e2f-3a4b-5678-2345-789012345678', 'e1f2a3b4-c5d6-7890-4567-901234567890', 80, 15, 200),
('77c88d99-e00f-11a2-2233-bbccddeeffaa', '华为超级快充移动电源', '20000mAh高密度锂聚合物大容量电芯，支持66W双向超级快充自充回血迅速，兼容SCP与PD 3.0主流快充协议，可为轻薄笔记本应急供电续航，USB-C与USB-A双接口同时输出双设备共享', 399.00, 'huawei_powerbank.jpg', '0d1e2f3a-4b5c-6789-3456-890123456789', 'a1b2c3d4-e5f6-7890-abcd-ef1234567890', 250, 40, 600),
('88d99e00-f11a-22b3-3344-ccddeeffaabb', '小米移动电源3', '20000mAh高密度锂聚合物优质电芯，USB-C双向45W大功率快充可为轻薄笔记本应急供电续航，三口独立输出同时充三台不同类型设备，小电流充电模式精准适配蓝牙耳机手环等微电流穿戴设备', 199.00, 'xiaomi_powerbank3.jpg', '0d1e2f3a-4b5c-6789-3456-890123456789', 'b2c3d4e5-f6a7-8901-bcde-f12345678901', 300, 50, 700),
('99e00f11-a22b-33c4-4455-ddeeffaabbcc', '苹果MagSafe充电器', '内置磁吸模组自动精确定位吸附无线充电区域，支持15W峰值快充功率稳定输出，兼容iPhone 12及后续全系列机型系统，配合MagSafe官方保护壳吸附更稳固，即放即充单手操作方便快捷', 329.00, 'apple_magsafe.jpg', '1e2f3a4b-5c6d-7890-4567-901234567890', 'c3d4e5f6-a7b8-9012-cdef-123456789012', 180, 30, 450),
('00f11a22-b33c-44d5-5566-eeffaabbccdd', '华为超级快充充电器', '66W超级快充兼容SCP与FCP私有快充协议，向下适配40W与22.5W多档安全功率输出，折叠插脚设计便携收纳出差友好，内置智能温控芯片实时监控温度保障充电安全，广泛兼容华为全系手机平板', 199.00, 'huawei_charger66w.jpg', '1e2f3a4b-5c6d-7890-4567-901234567890', 'a1b2c3d4-e5f6-7890-abcd-ef1234567890', 220, 35, 550),
('11a22b33-c44d-55e6-6677-ffaabbccddee', '小米Type-C数据线', 'Type-C双头快充数据线支持6A大电流与100W PD大功率快充协议，USB 2.0标准传输速率480Mbps，1.5米加长高密度编织线身柔韧耐弯折，内置E-Marker智能识别芯片自动匹配最佳充电功率', 39.00, 'xiaomi_usbcable.jpg', '2f3a4b5c-6d7e-8901-5678-012345678901', 'b2c3d4e5-f6a7-8901-bcde-f12345678901', 500, 100, 1500),
('bbb22c33-d44e-55f6-6677-112233445566', '苹果Lightning数据线', 'Apple MFi官方认证Lightning转USB-C快充数据线，支持PD快充协议兼容iPhone全系列机型，1米长度日常桌面使用便捷，原装C94芯片稳定识别不弹窗报警，数据传输与快速充电功能合二为一', 149.00, 'apple_lightning.jpg', '2f3a4b5c-6d7e-8901-5678-012345678901', 'c3d4e5f6-a7b8-9012-cdef-123456789012', 400, 80, 1200),
